// 远程调用后台FU查询客户端拷贝
async function IQueryClientCopys(projectID) {
    console.log("进入调用函数查询客户端拷贝");
    const param = new StringMap({
        type: 21001,
        cloudID: $Variable.cloudID,
    });

    let strParaMap = new StringMap({});
    strParaMap._insert("projectID", projectID, "uint64");
    let strmapPara = new Variant(strParaMap);

    const input = new StringMap({
        identifierType: CALL_BY_NAME,
        name: APPName,
        funcname: "IQueryClients",
        params: [strmapPara],
    });

    const res5 = await Call(param, input);
    console.log("远程调用后台APP查询客户端拷贝，res = ", res5);
    const ret = res5.errorcodes[0];
    if (0 != ret) {
        return {
            ret: ret,
        }
    }
    const data = res5.returndata;
    if (data.errorcode == 0) {
        return {
            ret: data.errorcode,
            data: data.returndata
        }
    } else {
        return {
            ret: data.errorcode
        }
    }
}

