    // 如果没有获取到实例基本信息，则直接返回
    if (!newData || Object.keys(newData).length === 0)
    {
        return;
    }

    // 创建参数
    const param = new StringMap({
        instanceRootRepoGuid: $Variable.工程Root时空仓库GUID,
        instanceRepoGuid: currentSelectedInstance.guid
    });

