 */
function _switchSpaceTime()
{
    return new Promise(resolve =>
    {
        const runInfo = {
            stType: 5, //时空信息标识,按照ID
            spaceTime: $Variable.配置后台时空对象全路径
        }
        SetRunInfo(runInfo, function (res)
        {
            const { ret } = res;
            if (ret !== 0)
            {
                console.error("[E] 切换时空信息失败, res = ", res);
            }
            const returnRes = ret === 0 ? true : false;
            resolve(returnRes);
        })
    });
}

