function _getDefaultExpandedNodeIds(treeData, level = 1)
{
    const treeDefaultExpandLevel = $Variable.treeDefaultExpandLevel;

    console.log("level = ", level, " || treeData = ", treeData);

    let nodeIds = [];

    if (level < treeDefaultExpandLevel)
    {
        let childrenTreeDatas = [];

        for (let i = 0; i < treeData.length; i++)
        {
            nodeIds.push(treeData[i].id);
            childrenTreeDatas = childrenTreeDatas.concat(treeData[i].children || []);
        }

        level++;

        if (childrenTreeDatas.length)
        {
            nodeIds = nodeIds.concat(_getDefaultExpandedNodeIds(childrenTreeDatas, level));
        }

    }

    return nodeIds;


}


