// 将列表数据转换为树形数据
function _compileListDataToTreeData(datas)
{
    datas.sort((suf, pre) => suf.name.localeCompare(pre.name))
    // 构建哈希索引
    const nodeMap = datas.reduce((acc, node) =>
    {
        // 将节点数据转换为树形结构
        acc[node.guid] = {
            ...node,
            label: node.name,
            hoverShow: false,
            icon: "kf-icon-root"
        };
        return acc;
    }, {});

    const tree = [];

    // 遍历节点数据
    datas.forEach(node =>
    {
        // 如果节点有父节点，并且父节点在哈希索引中存在
        if (node.parentguid && nodeMap[node.parentguid])
        {
            // 如果父节点有子节点，则将当前节点添加到父节点的子节点数组中
            if (nodeMap[node.parentguid].children)
            {

                nodeMap[node.parentguid].children.push(nodeMap[node.guid]);
            } else
            {
                // 如果父节点没有子节点，则创建一个子节点数组，并将当前节点添加到数组中
                nodeMap[node.parentguid].children = [nodeMap[node.guid]];
            }
        } else
        {
            // 如果节点没有父节点，则将当前节点添加到树形结构中
            tree.push(nodeMap[node.guid]);
        }
    });

    // 返回树形结构
    return tree;
}

