async function _FindIdByGuid(guid, type)
{
    let ConfigModelCopyId = "";
    const param = new StringMap({
        cloudID: cloudId,
        type: type,
        clientLocal: false
    });

    let input = new StringMap({});
    input._insert("cmdCode", QUERY_GUID_BY_ID, "int32");
    input._insert("guid", [guid], "string[]");

    const res = await Query(param, input);

    if (SUCCESS_CODE != res.ret)
    {
        console.log("通过guid查询id失败，res = ", res);
        return ConfigModelCopyId;
    }
    const output = res.output;
    const ids = output.id;
    if (0 === ids.length)
