async function _updateInstanceTreeNode(oldInstanceGuid, newInstanceGuid)
{
    // 获取新实例信息
    const newInstanceInfo = await _getInstanceInfo(newInstanceGuid);
    if (!newInstanceInfo)
    {
        _showMessage("获取实例信息失败");
        return;
    }

    // 获取旧节点的父节点信息
    const oldInstanceTreeNode = spaceTimeRepo_ElementTree.GetNode(oldInstanceGuid);
    if (!oldInstanceTreeNode)
    {
        return;
    }
    const parentNodeGuid = oldInstanceTreeNode.parentguid;
    const parentNode = spaceTimeRepo_ElementTree.GetNode(parentNodeGuid);

    if (!parentNode)
    {
        return;
    }

    // 删除旧节点
    spaceTimeRepo_ElementTree.Remove(oldInstanceTreeNode);

    // 追加新节点
    spaceTimeRepo_ElementTree.Append(parentNode, newInstanceTreeNode);

}

async function _getInstanceInfo(guid)
{
    const funcName = "IQueryInstanceBasicInfoByGuid";
    const param = new StringMap({
        guid: guid
    });
    const params = [new Variant(param)];
    const funcRes = await _remoteCall(funcName, params);


    if (!funcRes || funcRes.errorcode !== SUCCESS_CODE || !funcRes.returndata)
    {
        console.error("[E] 查询实例仓库信息失败, funcRes = ", funcRes);
        _showMessage("查询实例仓库信息失败");
        return false;
    }

    const repoInfo = funcRes.returndata;
    return repoInfo;
}


/**
 * @description: 异步函数，用于远程调用接口
 * @author: zhijie.wang
 * @date 2025-8-1
 * @param {String} funcName 
 * @param {StringMap} params 
 * @returns Promise<Object>
 * 步骤:
 *      1. 获取远程APP对象ID
 *      2. 构造输入参数
 *      3. 调用平台接口
 *      4. 判断调用结果
 *      5. 返回远程输出
 */
async function _remoteCall(funcName, params)
{
    if (!$Variable.isSyetemInitedSuccessed)
    {
        _showMessage("系统初始化失败, 无法远程调用后台函数!");
        return;
    }

    if (!await _switchSpaceTime())
    {
        _showMessage("切换页面时空对象失败", "error");
        return;
    }

    // 构造参数
    const param = new StringMap({
        type: TYPE_META_FU_OBJECT,
        cloudId: cloudId,
        timeout: 100 * 1000
    });

    // 构造输入参数
    const input = new StringMap({
        identifierType: IDENTIFIER_TYPE_ENUM.NAME,
        name: $Variable.配置后台APP对象名称,
        funcname: funcName,
        params: params
    });

    // 调用远程接口
    const res = await Call(param, input);

    // 打印调用结果
    console.log(`[I] 远程调用接口 <${funcName}>, res = `, res);

    // 判断调用结果是否成功
    if (res.ret != SUCCESS_CODE || !res.returndata)
    {
        // 构造错误信息
        const errorMessage = `远程调用接口 <${funcName}> 失败, ret = ${res.ret}`;
        console.error(`[E] ${errorMessage}, param = `, param);
        console.error(`[E] ${errorMessage}, input = `, input);
        console.error(`[E] ${errorMessage}, res = `, res);
        return;
    }

    // 返回调用结果
    return res.returndata;
}

/**
 * @author: zhijie.wang
 * @description: 调用生成器函数, 切换页面时空
 * @returns Promise<Boolean>
 */
function _switchSpaceTime()
{
    return new Promise(resolve =>
    {
        const runInfo = {
            stType: 5, //时空信息标识,按照ID
            spaceTime: $Variable.配置后台时空对象全路径
        }
        SetRunInfo(runInfo, function (res)
        {
            const { ret } = res;
            if (ret !== 0)
            {
                console.error("[E] 切换时空信息失败, res = ", res);
            }
            const returnRes = ret === 0 ? true : false;
            resolve(returnRes);
        })
    });
}



