async function main()
{
    if (Object.keys($Variable.currentSpaceTimeRepo).length === 0)
    {
        _showMessage("请选择时空节点", "warning");
        return;
    }

    if ($Variable.currentSpaceTimeRepo.guid == $Variable.工程Root时空仓库GUID)
    {
        _showMessage("实例根仓库下不允许创建实例", "warning");
        return;
    }

    const instanceType = await _selectInstanceType();
    if (instanceType == null)
    {
