    }

    if (instanceType != Enum_InstanceType.DCE_INSTANCE && instanceType != Enum_InstanceType.MCM_INSTANCE)
    {
        _showMessage("请选择正确的实例类型", "warning");
        return;
    }

    let createRes = false;
    if (instanceType == Enum_InstanceType.DCE_INSTANCE)
    {
