/**
 * @author: zhijie.wang
 * @description: 获取工厂模型根仓库信息
 * @returns Promise<undefined | boolean>
 * @steps:
 *      1. 获取当前页面的拷贝guid
 *      2. 获取当前页面拷贝所在的仓库信息
 *      3. 获取当前页面拷贝所在的仓库的父仓库（产品根仓库）信息
 *      4. 获取产品根仓库下的所有二级仓库信息
 */
async function _queryModelingRootRepoInfo()
{
    // 获取当前页面的拷贝id
    const currentPageInfo = await _getPageInfo();
    console.log("-I- <数字孪生实例化_框架页面> currentPageInfo = ", currentPageInfo);
    if (!currentPageInfo || !Object.keys(currentPageInfo).length || !currentPageInfo.guid)
    {
        console.error("-E- <数字孪生实例化_框架页面> 查询当前页面基本信息失败 currentPageInfo = ", currentPageInfo)
        return;
    }

    // 获取当前页面模型拷贝所在的仓库guid
    const currentPageCopyType = currentPageInfo.type;
    const currentPageCopyGuid = currentPageInfo.guid;
    const currentPageCopyInfo = await _getMDBModelCopyPropertyByGuid(currentPageCopyType, currentPageCopyGuid, ["$repositoryGuid"]);
    if (!currentPageCopyInfo || !Object.keys(currentPageCopyInfo).length)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBModelCopyPropertyByGuid 获取页面模型信息失败");
        return;
    }

    const currentPageCopyRepoGuid = currentPageCopyInfo.$repositoryguid;

    // 获取当前页面模型拷贝所在的仓库的父仓库guid
    const currentPageCopyRepoInfo = await _getMDBRepoPropertyByGuid(currentPageCopyRepoGuid, ["$parentGuid"]);
    if (!currentPageCopyRepoInfo || !Object.keys(currentPageCopyRepoInfo).length)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBRepoPropertyByGuid 获取页面模型所在仓库信息失败");
        return;
    }
    const currentPageCopyRepoParentGuid = currentPageCopyRepoInfo.$parentguid;


    let generation = 1;
    let filter = "";
    // 过滤查询父仓库guid下的组件仓库guid(数字孪生模型仓库)
    const modelingRepoName = $Variable.数字孪生模型仓库名称;
    filter = `$name == "${modelingRepoName}"`;
    let descendantRepoList = await _getMDBRepoDescendantReposByGuid(currentPageCopyRepoParentGuid, generation, filter, ["$guid", "$name", "$id", "$description"]);
    if (!descendantRepoList || descendantRepoList.length !== 1 || !Object.keys(descendantRepoList[0]).length)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBRepoDescendantReposByGuid 获取数字孪生模型仓库信息失败:: descendantRepoList = ", descendantRepoList);
        return;
    }
    const modelingRepoGuid = descendantRepoList[0].$guid;

    // 获取管控单元模型和采集设备模型仓库信息
    const mcmModelRepoName = $Variable.管控单元模型仓库名称;
    const dceModelRepoName = $Variable.采集设备模型仓库名称;
    generation = 1;
    filter = `$name == "${mcmModelRepoName}" || $name == "${dceModelRepoName}"`;
    descendantRepoList = await _getMDBRepoDescendantReposByGuid(modelingRepoGuid, generation, filter, ["$guid", "$name", "$id", "$description"]);
    if (!descendantRepoList || descendantRepoList.length !== 2)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBRepoDescendantReposByGuid 获取管控单元模型和采集设备模型仓库信息失败:: descendantRepoList = ", descendantRepoList);
        return;
    }

    const mcmModelRepo = descendantRepoList.filter(repo => repo.$name === mcmModelRepoName);
    const dceModelRepo = descendantRepoList.filter(repo => repo.$name === dceModelRepoName);

    $Variable.管控单元模型仓库信息 = {
        guid: mcmModelRepo[0].$guid,
        name: mcmModelRepo[0].$name,
        id: mcmModelRepo[0].$id,
        description: mcmModelRepo[0].$description
    };

    $Variable.采集设备模型仓库信息 = {
        guid: dceModelRepo[0].$guid,
        name: dceModelRepo[0].$name,
        id: dceModelRepo[0].$id,
        description: dceModelRepo[0].$description
    };
    return true;
}

/**
 * @author: zhijie.wang
 * @description: 获取 <业务运行管理_运行后台APP> 的模型信息
 * @returns Promise<undefined | boolean>
 * @steps:
 *      1. 获取当前页面的拷贝guid
 *      2. 获取当前页面拷贝的模型所在仓库guid（即实例化组件仓库的guid）
 *      3. 过滤查询组件仓库中的业务运行后台APP模型信息（kindIndex == 1002）
 */
async function _queryRunningMngEntityModelInfo()
{
    debugger;
    // 获取当前页面的拷贝id
    const currentPageInfo = await _getPageInfo();
    if (!currentPageInfo || !Object.keys(currentPageInfo).length || !currentPageInfo.guid)
    {
        console.error("-E- <数字孪生实例化_框架页面> 查询当前页面基本信息失败 currentPageInfo = ", currentPageInfo)
        return;
    }

    // 获取当前页面模型拷贝的模型guid和版本
    const currentPageCopyType = currentPageInfo.type;
    const currentPageCopyGuid = currentPageInfo.guid;
    const currentPageCopyInfo = await _getMDBModelCopyPropertyByGuid(currentPageCopyType, currentPageCopyGuid, ["$modelGuid", "$modelVersion"]);
    if (!currentPageCopyInfo || !Object.keys(currentPageCopyInfo).length)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBModelCopyPropertyByGuid 获取页面模型信息失败");
        return;
    }

    // 获取当前页面拷贝的模型所在仓库guid（即实例化组件仓库的guid）
    const currentPageModelGuid = currentPageCopyInfo.$modelguid;
    const currentPageModelVersion = currentPageCopyInfo.$modelversion;
    const currentPageModelType = currentPageCopyType - 20;
    const currentPageModelInfo = await _getMDBModelPropertyByGuid(currentPageModelType, currentPageModelGuid, currentPageModelVersion, ["$repositoryGuid"]);
    if (!currentPageModelInfo || !Object.keys(currentPageModelInfo).length)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBModelPropertyByGuid 获取页面拷贝的模型信息失败");
        return;
    }

    // 查询实例化组件仓库下的配置后台仓库（数字孪生实例化_实例化_配置后台）
    const currentPageModelRepoGuid = currentPageModelInfo.$repositoryguid;
    const auRepoName = "数字孪生实例化_实例化_配置后台";
    let generation = 1;
    let filter = `$name == "${auRepoName}"`;
    let auRepos = await _getMDBRepoDescendantReposByGuid(currentPageModelRepoGuid, generation, filter, ["$guid", "$name", "$id", "$description"]);
    if (!auRepos || auRepos.length !== 1 || !Object.keys(auRepos[0]).length)
    {
        console.error("-E- <数字孪生实例化_框架页面> _getMDBRepoDescendantReposByGuid 获取实例化组件仓库下的配置后台仓库 :: 失败:: auRepos = ", auRepos);
        return;
    }
    const auRepoGuid = auRepos[0].$guid;

    // 查询AU仓库下的APP拷贝
    const runningMngAppModelName = `实例配置`;
    const kindIndex = "1002";
    // const runningMngAppModelFilter = `$name == "${runningMngAppModelName}"`;
    const runningMngAppModelFilter = `kindIndex == "${kindIndex}"`;
    const runningMngAppModelInfo = await _getMDBRepoDescendantDatasByRepoGuid(Enum_MDBModelType.TYPE_ENTITY_MODEL, auRepoGuid, 1, runningMngAppModelFilter, ["$id", "$guid", "$name", "$version", "$type"]);
    if (!runningMngAppModelInfo || runningMngAppModelInfo.length !== 1 || !Object.keys(runningMngAppModelInfo[0]).length)
    {
        console.error(`-E- 查找 ${runningMngAppModelName} 失败！runningMngAppModelInfo = `, runningMngAppModelInfo);
        return;
    }

    // 获取APP模型的所有版本信息
    const runningMngAppModelGuid = runningMngAppModelInfo[0].$guid;
    const runningMngAppModelType = runningMngAppModelInfo[0].$type;
    const runningMngAppModelVersions = await _getMDBModelVersionListByGuid(runningMngAppModelType, runningMngAppModelGuid, returnFields = ["$id", "$name", "$guid", "$repositoryGuid", "$version"]);
    if (!runningMngAppModelVersions || !runningMngAppModelVersions.length)
    {
        console.error(`-E- 查找 ${runningMngAppModelName} 的历史版本列表失败！ runningMngAppModelVersions = `, runningMngAppModelVersions);
        return;
    }

    // 获取最新版本的模型信息
    let latestRunningMngAppModelInfo = runningMngAppModelVersions[0];
    for (let i = 1; i < runningMngAppModelVersions.length; i++)
    {
        if (runningMngAppModelVersions[i].$version > latestRunningMngAppModelInfo.$version)
        {
            latestRunningMngAppModelInfo = runningMngAppModelVersions[i];
        }
    }

    $Variable.业务运行管理APP模型信息 = {
        id: latestRunningMngAppModelInfo.$id,
        guid: latestRunningMngAppModelInfo.$guid,
        version: latestRunningMngAppModelInfo.$version,
        name: latestRunningMngAppModelInfo.$name
    };

    return true;
}

