/**
 * @description 调用接口查询模型库数据
 * @author: zhijie.wang
 * @date 2025-9-8
 * @param {Object} funcParam 参数
 * @param {Object} funcInput 参数
 * @returns {Promise<Array<Object> | undefined>} 接口返回的数据
 */
async function _queryMDBDataInfo(funcParam, funcInput)
{
    const paramObj = {
        cloudId: cloudId,
        timeout: 30 * 1000
    };

    Object.keys(funcParam).forEach(key =>
    {
        paramObj[key] = funcParam[key];
    });

    if (!paramObj.type)
    {
        console.error("-E- 参数错误, 请检查参数: type");
        return;
    }

    const inputObj = {
        returnFields: ["$id", "$name", "$guid", "$repositoryGuid"]
    };
    Object.keys(funcInput).forEach(key =>
    {
        inputObj[key] = funcInput[key];
    });

    const param = new StringMap(paramObj);
    const input = new StringMap(inputObj);
    const res = await Query(param, input);
    if (res.ret !== SUCCESS_CODE || !res.output || !res.output.returndata)
    {
        console.error("-E- 查询失败: res = ", res);
        return;
    }
    return res.output.returndata;
}

