function _compileListDataToTreeData(datas)
{
    // 构建哈希索引
    const nodeMap = datas.reduce((acc, node) =>
    {

        let customContentShow = true;

        if (node.id === $Variable.工厂实例根仓库ID)
        {
            customContentShow = false;
        }

        // 将节点数据转换为树形结构
        acc[node.guid] = {
            ...node,
            label: node.name,
            customContentShow: [customContentShow],
            hoverShow: false,
        };
        return acc;
    }, {});

    const tree = [];

    // 遍历节点数据
    datas.forEach(node =>
    {
        // 如果节点有父节点，并且父节点在哈希索引中存在
        if (node.parentguid && nodeMap[node.parentguid])
        {
            // 如果父节点有子节点，则将当前节点添加到父节点的子节点数组中
            if (nodeMap[node.parentguid].children)
            {

                nodeMap[node.parentguid].children.push(nodeMap[node.guid]);
            } else
            {
                // 如果父节点没有子节点，则创建一个子节点数组，并将当前节点添加到数组中
                nodeMap[node.parentguid].children = [nodeMap[node.guid]];
            }
        } else
        {
            // 如果节点没有父节点，则将当前节点添加到树形结构中
            tree.push(nodeMap[node.guid]);
        }
    });

    // 返回树形结构
    return tree;
}

// 异步查询实例数据函数
async function _queryInstanceData(rootRepoId, parentId = "", keyWords = "")
{

    // 定义一个空数组，用于存储查询到的数据
    let datas = [];

    // 创建一个StringMap对象，用于存储查询参数
    const params = new StringMap();
    // 将工厂实例根仓库ID插入到参数中
    params._insert("factoryInstanceRootRepoId", rootRepoId, "uint64");

    // 定义查询函数名
    const funcName = "IQueryAllFactoryInstanceRepoList";

    // 调用远程调用函数，传入查询函数名和参数
    const funcRes = await _remoteCall(funcName, [new Variant(params)]);

    // 如果查询结果为空，则返回空数组
    if (!funcRes || funcRes.errorcode !== SUCCESS_CODE || !funcRes.returndata)
    {
        const errorMessage = `查询实例数据失败`;
        console.error(`[E] ${errorMessage}, funcRes = `, funcRes);
        _showMessage(errorMessage);
        return datas;
    }

    // 将查询结果中的返回数据赋值给datas数组
    datas = funcRes.returndata;

    // 返回查询到的数据
    return datas;
}

function _getDefaultExpandedNodeIds(treeData, level = 1)
{
    const treeDefaultExpandLevel = $Variable.treeDefaultExpandLevel;

    console.log("level = ", level, " || treeData = ", treeData);

    let nodeIds = [];

    if (level < treeDefaultExpandLevel)
    {
        let childrenTreeDatas = [];

        for (let i = 0; i < treeData.length; i++)
        {
            nodeIds.push(treeData[i].id);
            childrenTreeDatas = childrenTreeDatas.concat(treeData[i].children || []);
        }

        level++;

        if (childrenTreeDatas.length)
        {
            nodeIds = nodeIds.concat(_getDefaultExpandedNodeIds(childrenTreeDatas, level));
        }

    }

    return nodeIds;


}


