                // 如果父节点没有子节点，则创建一个子节点数组，并将当前节点添加到数组中
                nodeMap[node.parentguid].children = [nodeMap[node.guid]];
            }
        } else
        {
            // 如果节点没有父节点，则将当前节点添加到树形结构中
            tree.push(nodeMap[node.guid]);
        }
    });

    // 返回树形结构
    return tree;
}

