function publicEventHanlder(pageName, transferData)
{
    console.log("publicEventHanlder transferData = ", transferData);
    const { eventName, eventParam } = transferData;
    if (eventName == "Cancel")
    {
        CloseChild(pageName);
        return;
    } else if (eventName == "Confirm")
    {
        if (!eventParam || eventParam.length != 2)
        {
            _showMessage("公开事件传参错误");
            return;
        }

        const targetNode = eventParam[0];
        const moveMode = eventParam[1]; // 1:移动选中节点，2:移动选中节点的子孙节点
        if (moveMode == 1)
        {
            // 删除被移动的节点
            spaceTimeRepo_ElementTree.Remove($Variable.currentSpaceTimeRepo);
        } else
        {
            // 清空选中节点的子节点
            spaceTimeRepo_ElementTree.UpdateKeyChildren($Variable.currentSpaceTimeRepo.guid, []);
        }

        // 判断目标节点是否存在，如果存在则选中目标节点，如果不存在，则选中被移动节点的父节点
        if (spaceTimeRepo_ElementTree.GetNode(targetNode))
        {
            const targetNodeGuid = targetNode.guid;
            spaceTimeRepo_ElementTree.SetCurrentKey(targetNodeGuid);
            $Variable.currentSpaceTimeRepo = { ...targetNode };

        } else
        {
            const parentNodeGuid = $Variable.currentSpaceTimeRepo.parentguid;

            spaceTimeRepo_ElementTree.SetCurrentKey(parentNodeGuid);

            const parentNode = spaceTimeRepo_ElementTree.GetCurrentNode();

            console.log("[D] 获取到当前选中的节点 parentNode = ", parentNode);

            $Variable.currentSpaceTimeRepo = { ...parentNode };
        }




        // console.log("[D] 被移动节点的父节点 id = ", parentNodeGuid);

