async function getSourceCopyInfo(queryComponentRepoName, queryCopyNames)
{

    // 获取当前页面的拷贝id
    let currentPageInfo = await getPageInfo();
    if (currentPageInfo.ret !== 0)
    {
        _showMessage("查询当前页面基本信息失败");
        return
    }

    let copyId = currentPageInfo.data.copyId;

    // 查询当前页面拷贝的私有仓库
    let copyInfo = await getMDBProperty(copyId, 1025, ["$id", "$name", "$modeldbrepository"]);
    if (copyInfo.ret !== 0)
    {
        _showMessage("查询当前页面拷贝私有仓库失败, ret = ", copyInfo.ret);
        return
    }

    if (!copyInfo.output.returndata || !copyInfo.output.returndata.length)
    {
        _showMessage("查询当前页面拷贝私有仓库失败:: 未查到私有仓库信息");
        return;
    }

    let repository = copyInfo.output.returndata[0].$modeldbrepository;

    // 根据私有仓库guid查id
    let repositoryId = await _FindIdByGuid(repository.guid, 1001);
    if (!repositoryId)
    {
        _showMessage("根据当前页面的仓库guid查仓库id失败");
        return
    }
    let targetId = repositoryId;

    if (queryComponentRepoName !== repository.name)
    {
        // 查询指定仓库的属性
        let parentRepository = await getMDBProperty(repositoryId, 1001, ["$repositoryid"]);
        if (parentRepository.ret !== 0)
        {
            _showMessage("查询当前页面拷贝所在的仓库父仓库id失败");
            return;
        }

        parentRepository = parentRepository.output.returndata[0].$repositoryid;

        // 查询指定仓库的子仓库
        let childRepositoryList = await getDataByParentRep(parentRepository, 1001, `$name == ${queryComponentRepoName}`);
        if (childRepositoryList.ret !== 0)
        {
            _showMessage("查询当前页面拷贝所在仓库的同级仓库失败");
            return;
        }

        if (!childRepositoryList.output.returndata || !childRepositoryList.output.returndata.length)
        {
            _showMessage("查询当前页面拷贝所在仓库的同级仓库失败:: 未查到同级仓库");
            return;
        }

        targetId = childRepositoryList.output.returndata[0].$id;
    }

    let copyList = await getDataByParentRep(targetId, 1025, "");
    if (copyList.ret !== 0)
    {
        _showMessage("查询指定仓库下的拷贝列表失败");
        return
    }

    let dataList = [];

    copyList.output.returndata.forEach(el =>
    {
        if (queryCopyNames.includes(el.$name))
        {
            dataList.push(el)
        }
    })
    return dataList;
}


