/**
 * @author: zhijie.wang
 * @description: 将列表数据转换为树形数据
 * @param {Array<Object>} datas 
 * @returns 
 * 步骤：
 *      1. 构建哈希索引，将节点数据转换为树形结构，并添加label和customContentShow属性
 *      2. 创建树结构，将节点数据转换为树形结构
 *      3. 返回树形结构
 */
function _compileListDataToTreeData(datas)
{
    datas.sort((suf, pre) => suf.name.localeCompare(pre.name, 'zh-Hans-CN', { numeric: true }));
    
    // 构建哈希索引
    const nodeMap = datas.reduce((acc, node) =>
    {
        // 将节点数据转换为树形结构，并添加label和customContentShow属性
        acc[node.guid] = {
            ...node,
            label: node.name,
            customContentShow: [true],
            hoverShow: false,
            icon: node.instancetype === "1" ? "kf-icon-model" : "kf-icon-root"
        };
        return acc;
    }, {});

    const treeData = [];

    // 遍历节点数据
    datas.forEach(node =>
    {
        // 如果节点有父节点，并且父节点在哈希索引中存在
        if (node.parentguid && nodeMap[node.parentguid])
        {
            // 如果父节点有子节点，则将当前节点添加到父节点的子节点数组中
            if (nodeMap[node.parentguid].children)
            {
                nodeMap[node.parentguid].children.push(nodeMap[node.guid]);
            } else
            {
                // 如果父节点没有子节点，则创建一个子节点数组，并将当前节点添加到数组中
                nodeMap[node.parentguid].children = [nodeMap[node.guid]];
            }
        } else
        {
            // 如果节点没有父节点，则将当前节点添加到树形结构中
            treeData.push(nodeMap[node.guid]);
        }
    });

    // 返回树形结构
    return treeData;
}


/**
 * @description: 异步函数，用于远程调用接口
 * @author: zhijie.wang
 * @date 2025-8-1
 * @param {String} funcName 
 * @param {StringMap} params 
 * @returns Promise<Object>
 * 步骤:
 *      1. 获取远程APP对象ID
 *      2. 构造输入参数
 *      3. 调用平台接口
 *      4. 判断调用结果
 *      5. 返回远程输出
 */
async function _remoteCall(funcName, params)
{
    if (!$Variable.isSyetemInitedSuccessed)
    {
        _showMessage("系统初始化失败, 无法远程调用后台函数!");
        return;
    }

    if (!await _switchSpaceTime())
    {
        _showMessage("切换页面时空对象失败", "error");
        return;
    }

    // 构造参数
    const param = new StringMap({
        type: TYPE_META_FU_OBJECT,
        cloudId: cloudId,
        timeout: 100 * 1000
    });

    // 构造输入参数
    const input = new StringMap({
        identifierType: IDENTIFIER_TYPE_ENUM.NAME,
        name: $Variable.配置后台APP对象名称,
        funcname: funcName,
        params: params
    });

    // 调用远程接口
    const res = await Call(param, input);

    // 打印调用结果
    console.log(`[I] 远程调用接口 <${funcName}>, res = `, res);

    // 判断调用结果是否成功
    if (res.ret !== SUCCESS_CODE || !res.returndata)
    {
        // 构造错误信息
        const errorMessage = `远程调用接口 <${funcName}> 失败, ret = ${res.ret}`;
        console.error(`[E] ${errorMessage}, param = `, param);
        console.error(`[E] ${errorMessage}, input = `, input);
        console.error(`[E] ${errorMessage}, res = `, res);
        return;
    }

    // 返回调用结果
    return res.returndata;
}

