function _compileToGetTaskTableData()
{
    // 组织呈这样的结构, 可以通过更新 repoGuidAndInfoMap 中的值来响应式更新界面
    const tableData = [];
    for (const [rootInstanceGuid, childInstanceGuids] of rootInstanceGuidAndChildInstanceGuidsMap)
