async function _queryReposByGuids(repoGuids, returnFields = ["$name", "$guid", "$parentguid", "$description"], options = { limit: 1000, funcDesc: "通过guids查询仓库信息" })
{
    const { limit, funcDesc } = options;
    const param = new StringMap({
        cloudId: getLocalCloudID(),
        type: 1001,
        timeout: limit * 5 * 1000
    });

    const input = new StringMap({
        identifierType: 5,
        // guids: repoGuids,
        returnFields: returnFields
    });

    let isAllSuccess = true;
    const repos = [];
    for (let i = 0; i < repoGuids.length; i += limit)
    {
        const queryGuids = repoGuids.slice(i, i + limit);
        input._insert("guids", queryGuids, "string[]");
        const res = await Query(param, input);
        if (!res || res.ret != 0 || !res.output || res.output.ret != 0 || !res.output.returndata || res.output.errorcodes.filter(item => item != 0).length > 0)
        {
            isAllSuccess = false;
            console.log(`[E] ${funcDesc} :: <_queryReposByGuids> :: 第 ${i + 1} ~ ${i + limit} 个 :: 失败 :: res = `, res);
            console.log(`[E] ${funcDesc} :: <_queryReposByGuids> :: 第 ${i + 1} ~ ${i + limit} 个 :: 失败 :: input = `, input);
            break;
        }
        repos.push(...(res.output.returndata));
        input._erase("guids");
    }
    return repos;
}

async function _queryChildReposByParentGuids(parentGuids, filter = "", returnFields = ["$name", "$guid", "$parentguid", "$description"], options = { limit: 200, funcDesc: "查询子仓库" })
{
    const { limit, funcDesc } = options;
    const param = new StringMap({
        cloudId: getLocalCloudID(),
        type: 1001,
        timeout: limit * 20 * 1000
    });

    const input = new StringMap({
        mode: 12,
        repoIdentifierType: 5,
        // repoGuids: parentGuids,
        generation: 1,
        returnFields: returnFields,
        filter: filter
    });

    let isAllSuccess = true;
    const childRepos = [];

    for (let i = 0; i < parentGuids.length; i += limit)
    {
        const subParentGuids = parentGuids.slice(i, i + limit);
        input._insert("repoGuids", subParentGuids, "string[]");
        const res = await Query(param, input);
        if (!res || res.ret != 0 || !res.output || res.output.ret != 0 || !res.output.returndata || res.output.errorcodes.filter(item => item != 0).length > 0)
        {
            isAllSuccess = false;
            console.log(`[E] ${funcDesc} :: <_queryChildReposByParentGuids> :: 第${i + 1} ~ ${i + limit} 个 :: 失败 :: res = `, res);
            console.log(`[E] ${funcDesc} :: <_queryChildReposByParentGuids> :: 第${i + 1} ~ ${i + limit} 个 :: 失败 :: input = `, input);
            break;
        }
        childRepos.push(...(res.output.returndata));
        input._erase("repoGuids");
    }
    if (!isAllSuccess)
    {
        return;
    }

    return childRepos;
}

async function _deleteRepoPackets(packetGuidAndVersionMap, options = { limit: 1000, funcDesc: "删除仓库数据包" })
{
    if (!packetGuidAndVersionMap || packetGuidAndVersionMap.size == 0)
    {
        return true;
    }
    const { limit, funcDesc } = options;
    const packetGuids = [...(packetGuidAndVersionMap.keys())];
    const packetVersions = [...(packetGuidAndVersionMap.values())];

    const param = new StringMap({
        cloudId: getLocalCloudID(),
        type: 1021,
        timeout: limit * 10 * 1000
    });

    const input = new StringMap({
        dealMode: 2,
        repoIdentifierType: 5,
        // guids: packetGuids,
        // versions: packetVersions
    });

    let isAllSuccess = true;
    for (let i = 0; i < packetGuids.length; i += limit)
    {
        const subPacketGuids = packetGuids.slice(i, i + limit);
        const subPacketVersions = packetVersions.slice(i, i + limit);
        input._insert("guids", subPacketGuids, "string[]");
        input._insert("versions", subPacketVersions, "int32[]");
        const res = await Delete(param, input);
        if (!res || res.ret != 0)
        {
            isAllSuccess = false;
            console.log(`[E] ${funcDesc} :: <_deleteRepoPackets> :: 第${i + 1} ~ ${i + limit} 个 :: 失败 :: res = `, res);
            console.log(`[E] ${funcDesc} :: <_deleteRepoPackets> :: 第${i + 1} ~ ${i + limit} 个 :: 失败 :: input = `, input);
            break;
        }
        input._erase("guids");
        input._erase("versions");
    }
    return isAllSuccess;
}

function _getRepoTypeStr(repoType)
{
    switch (repoType)
    {
        case Enum_RepoType.SPACE_TIME:
            return Enum_RepoTypeStr.SPACE_TIME;
        case Enum_RepoType.ROOT_INSTANCE:
            return Enum_RepoTypeStr.ROOT_INSTANCE;
        case Enum_RepoType.CHILD_INSTANCE:
            return Enum_RepoTypeStr.CHILD_INSTANCE;
        case Enum_RepoType.AU_ROOT_INSTANCE:
            return Enum_RepoTypeStr.AU_ROOT_INSTANCE;
        case Enum_RepoType.AU_CHILD_INSTANCE:
            return Enum_RepoTypeStr.AU_CHILD_INSTANCE;
        default:
            return Enum_RepoTypeStr.UNKNOWN;
    }
}

async function _exportFailedInstances()
{
    const confirmRes = await _confirmMessage("提示", "有提交失败的数据, 是否导出错误信息?",);
    if (!confirmRes)
    {
        return;
    }

    const exportedData = [];

    for (const [guid, repo] of repoGuidAndInfoMap)
    {
        if (repo.errorCode == Enum_ErrorCode.SUCCESS)
        {
            continue;
        }
        exportedData.push({
            名称: repo.name,
            类型: _getRepoTypeStr(repo.repoType),
            全名称: repo.fullName,
            错误码: repo.errorCode,
            错误信息: repo.errorMessage,
            GUID: repo.guid,
        });
    }

    if (!exportedData.length)
    {
        return;
    }
    ExportToExcel(exportedData, `版本提交错误_${new Date().format("yyyy_MM_dd_hh_mm_ss")}`, { inputFormat: 0 })
}


async function _asyncCreatePacket(repoGuids, dataFields, dataValues)
{
    return new Promise(async (resolve, reject) =>
    {
        try
        {
            const returnData = [];
            const _asyncCreatePacketCallback = function (result)
            {
                debugger;
                console.log(`[D] _asyncCreatePacketCallback, result = `, result);
                const errorCodes = result.errorcodes;
                const guids = result.guids || repoGuids;
                const versions = result.versions || [];
                for (let i = 0; i < errorCodes.length; i++)
                {
                    const guid = guids[i];
                    const errorCode = errorCodes[i];
                    let errorMessage = "打包成功";
                    const packetVersion = versions[i];
                    if (errorCode != 0)
                    {
                        errorMessage = `打包回调报错 :: errorCode = ` + errorCode;
                        console.log(`[E] ${errorMessage}`);
                    }
                    returnData.push({ guid, errorCode, errorMessage, packetVersion });
                }
                _compilePacketResults(returnData);
                resolve(returnData);
            };
            const param = new StringMap({
                cloudId: getLocalCloudID(),
                type: 1062,
                timeout: repoGuids.length * 120 * 1000,
                callbackFuncName: _asyncCreatePacketCallback
            });
            const taskName = "实例版本提交任务_" + new Date().format("yyyy_MM_dd_hh_mm_ss_S");
            const input = new StringMap({
                taskName: taskName,
                taskKind: 7,
                identifierType: 5,
                guids: repoGuids,
                dataFields: dataFields,
                dataValues: dataValues
            });

            const result = await AsyncCreate(param, input);
            // console.log(`[D] _asyncCreatePacket, result = `, result);
            if (result.ret != 0 || !result.output || result.output.ret != 0 || result.output.errorcodes.filter(item => item != 0).length > 0)
            {
                console.log(`[E] <_asyncCreatePacket>, result = `, result);
                console.log(`[E] <_asyncCreatePacket>, repoGuids = `, repoGuids);
                for (let i = 0; i < repoGuids.length; i++)
                {
                    const guid = repoGuids[i];
                    const errorCode = result.output && result.output.errorcodes ? result.output.errorcodes[i] : result.ret;
                    const errorMessage = "创建打包任务失败 :: result = " + JSON.stringify(result);
                    const packetVersion = -1;
                    returnData.push({ guid, errorCode, errorMessage, packetVersion });
                }
                _compilePacketResults(returnData);
                resolve(returnData);
            }
        }
        catch (error)
        {
            console.log(`[E] _asyncCreatePacket, error = `, error);
            reject(error);
        }
    });
}


function _showMessage(massage, type = "error")
{
    const options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true,
    };
    ShowMessage(options);
}

function _confirmMessage(title, message, isHtml = true)
{
    return new Promise(resolve =>
    {
        ShowMsgBox("confirm", {
            type: "warning",
            title: title,
            message: message,
            isHtml
        }, (res) =>
        {
            if (res.action === "confirm")
            {
                resolve(true);
            } else
            {
                resolve(false);
            }
        });
    });
}

