// 处理打包结果数据 ==================================================================== START

function _compilePacketResults(packetResults)
{
    for (const packetResult of packetResults)
    {
        if (packetResult.errorCode == Enum_ErrorCode.SUCCESS)
        {
            _compileSuccessResult(packetResult);
        } else
        {
            _compileFailedResult(packetResult);
        }
    }
    _updateTaskProgress();

}

function _compileSuccessResult(result)
{
    const { guid, errorCode, errorMessage, packetVersion } = result;
    const info = repoGuidAndInfoMap.get(guid);
    packetGuidAndVersionMap.set(guid, packetVersion);
    info.packetVersion = packetVersion;

    if (info.errorCode == Enum_ErrorCode.SUCCESS)
    {
        completedCount++;
        info.taskStatus = Enum_taskStatus.Completed;
    }

    let compiledGuid = info.guid;
    while (repoGuidAndInfoMap.has(compiledGuid))
    {
        const repoInfo = repoGuidAndInfoMap.get(compiledGuid);
        if (repoInfo.errorCode == Enum_ErrorCode.SUCCESS)
        {
            repoInfo.completedCount += 1;
            const progressValue = _calcProgressValue(repoInfo.totalCount, repoInfo.completedCount);
            let progressStatus = "warning";
            let taskMessage = "提交中";
            if (progressValue >= 100)
            {
                progressStatus = "success"
                taskMessage = "提交成功";
            }
            repoInfo.progress.value = progressValue;
            repoInfo.progress.status = progressStatus;
            repoInfo.errorMessage = taskMessage;
        }
        compiledGuid = repoInfo.parentGuid;
    }

}


function _compileFailedResult(result)
{
    const { guid, errorCode, errorMessage } = result;
    const info = repoGuidAndInfoMap.get(guid);
    info.taskStatus = Enum_taskStatus.Error;
    info.errorCode = errorCode;
    info.errorMessage = errorMessage;
    info.progress.value = 100;
    info.progress.showText = false;
    info.progress.status = "exception";
    const currentFullName = info.fullName;

    // 按照可能的打包先后顺序（和打包时push顺序有关）逐层处理失败：首先找到 rootInstanceGuid , 然后向下处理
    let rootInstanceGuid = "";

    if (childAuRepoGuidAndChildInstanceGuidMap.has(guid))
    {
        const childInstanceGuid = childAuRepoGuidAndChildInstanceGuidMap.get(guid);
        rootInstanceGuid = childInstanceGuidAndRootInstanceGuidMap.get(childInstanceGuid);
    }
    else if (childInstanceGuidAndRootInstanceGuidMap.has(guid))
    {
        rootInstanceGuid = childInstanceGuidAndRootInstanceGuidMap.get(guid);
    }
    else if (childAuRepoGuidAndRootInstanceGuidMap.has(guid))
    {
        rootInstanceGuid = childAuRepoGuidAndRootInstanceGuidMap.get(guid);
    }
    else if (rootInstanceGuidAndChildInstanceGuidsMap.has(guid))
    {
        rootInstanceGuid = guid;
    }


    let allRepoGuidsToCompiled = [rootInstanceGuid, ...(rootInstanceGuidAndChildAuRepoGuidsMap.get(rootInstanceGuid))];
    for (const childInstanceGuid of rootInstanceGuidAndChildInstanceGuidsMap.get(rootInstanceGuid))
    {
        allRepoGuidsToCompiled.push(childInstanceGuid);
        allRepoGuidsToCompiled.push(...(childInstanceGuidAndChildAuRepoGuidsMap.get(childInstanceGuid)));
    }
    allRepoGuidsToCompiled = [...new Set(allRepoGuidsToCompiled.filter(item => item != guid))];

    // const spaceTimeRepo = repoGuidAndInfoMap.get(spaceTimeRepoGuid);
    const message = `${currentFullName} :: ${errorMessage}`;
    for (const repoGuid of allRepoGuidsToCompiled)
    {
        invalidPacketGuidsSet.add(repoGuid);
        const repoInfo = repoGuidAndInfoMap.get(repoGuid);
        if (repoInfo.errorCode == Enum_ErrorCode.SUCCESS)
        {
            repoInfo.errorCode = Enum_ErrorCode.RELATE_FAILED;
            repoInfo.errorMessage = "相关联仓库提交失败 :: " + message;;
            if (packetGuidAndVersionMap.has(repoGuid))
            {
                completedCount -= 1;
                // if (repoInfo.taskStatus == Enum_taskStatus.Completed)
                // {
                //     spaceTimeRepo.completedCount -= 1;
                // }
            }

            repoInfo.progress.value = 100;
            repoInfo.progress.status = "exception";
            repoInfo.progress.showText = false;
        }
        else if (repoInfo.errorCode == Enum_ErrorCode.RELATE_FAILED)
        {
            repoInfo.errorMessage += `, ${message}`;
        }
    }

}


function _compileAbortedGuids(guids)
{
    let rootInstanceGuids = [];
    for (const guid of guids)
    {
        let rootInstanceGuid = "";

        if (childAuRepoGuidAndChildInstanceGuidMap.has(guid))
        {
            const childInstanceGuid = childAuRepoGuidAndChildInstanceGuidMap.get(guid);
            rootInstanceGuid = childInstanceGuidAndRootInstanceGuidMap.get(childInstanceGuid);
        }
        else if (childInstanceGuidAndRootInstanceGuidMap.has(guid))
        {
            rootInstanceGuid = childInstanceGuidAndRootInstanceGuidMap.get(guid);
        }
        else if (childAuRepoGuidAndRootInstanceGuidMap.has(guid))
        {
            rootInstanceGuid = childAuRepoGuidAndRootInstanceGuidMap.get(guid);
        }
        else if (rootInstanceGuidAndChildInstanceGuidsMap.has(guid))
        {
            rootInstanceGuid = guid;
        }
        rootInstanceGuids.push(rootInstanceGuid);
    }

    // 去重
    rootInstanceGuids = [...new Set(rootInstanceGuids)];

    let allRepoGuidsToCompiled = [];
    for (const rootInstanceGuid of rootInstanceGuids)
    {
        allRepoGuidsToCompiled.push(rootInstanceGuid, ...(rootInstanceGuidAndChildAuRepoGuidsMap.get(rootInstanceGuid)));
        for (const childInstanceGuid of rootInstanceGuidAndChildInstanceGuidsMap.get(rootInstanceGuid))
        {
            allRepoGuidsToCompiled.push(childInstanceGuid);
            allRepoGuidsToCompiled.push(...(childInstanceGuidAndChildAuRepoGuidsMap.get(childInstanceGuid)));
        }
    }
    allRepoGuidsToCompiled = [...new Set(allRepoGuidsToCompiled)];

    for (const repoGuid of allRepoGuidsToCompiled)
    {
        const repoInfo = repoGuidAndInfoMap.get(repoGuid);

        if (repoInfo.taskStatus == Enum_taskStatus.Completed && repoInfo.errorCode == Enum_ErrorCode.SUCCESS)
        {
            if (packetGuidAndVersionMap.has(repoGuid))
            {
                completedCount -= 1;
            }
        }
        repoInfo.taskStatus = Enum_taskStatus.Aborted;
        repoInfo.errorCode = Enum_ErrorCode.ABORT;
        repoInfo.progress.value = 100;
        repoInfo.progress.status = "exception";
        repoInfo.progress.showText = false;
        invalidPacketGuidsSet.add(repoGuid);
    }
    _updateTaskProgress();
}

function _calcProgressValue(totalCount, completedCount)
{
    return Math.ceil((completedCount / totalCount) * 10000) / 100;
}


async function _compileInvalidRepoPackets()
{
    // 遍历 packetFailedRepoGuidSet，
    // 如果有失败的仓库，则该仓库的父仓库和子仓库对应的数据包都要删除
    if (invalidPacketGuidsSet.size == 0)
    {
        return true;
    }

    const repoPacketGuidAndVersionMapToBeDeleted = new Map();
    invalidPacketGuidsSet.forEach(repoGuid =>
    {
        if (packetGuidAndVersionMap.has(repoGuid))
        {
            repoPacketGuidAndVersionMapToBeDeleted.set(repoGuid, packetGuidAndVersionMap.get(repoGuid));
        }
    });

    if (!repoPacketGuidAndVersionMapToBeDeleted.size)
    {
        return true;
    }

    console.log("[D] <实例版本提交> :: 删除打包失败仓库相关的数据包 :: repoPacketGuidAndVersionMapToBeDeleted = ", repoPacketGuidAndVersionMapToBeDeleted);
    const deleteRes = await _deleteRepoPackets(repoPacketGuidAndVersionMapToBeDeleted);
    console.log("[D] <实例版本提交> :: 删除打包失败仓库相关的数据包 :: deleteRes = ", deleteRes);
    return deleteRes;

}


