async function _submitRepoVersions(packetDescription)
{
    const dataFields = ["$packetDescription"];
    const repoGuids = [];
    const dataValues = [];

    for (const [rootInstanceGuid, childInstanceGuids] of rootInstanceGuidAndChildInstanceGuidsMap)
    {
        if (!repoGuidAndInfoMap.has(rootInstanceGuid) || repoGuidAndInfoMap.get(rootInstanceGuid).errorCode != Enum_ErrorCode.SUCCESS) { continue; }

        for (const childInstanceGuid of childInstanceGuids)
        {
            if (!repoGuidAndInfoMap.has(childInstanceGuid) || repoGuidAndInfoMap.get(childInstanceGuid).errorCode != Enum_ErrorCode.SUCCESS) { continue }

            for (const auRepoGuid of childInstanceGuidAndChildAuRepoGuidsMap.get(childInstanceGuid))
            {
                if (!repoGuidAndInfoMap.has(auRepoGuid) || repoGuidAndInfoMap.get(auRepoGuid).errorCode != Enum_ErrorCode.SUCCESS) { continue }
                // 子实例的子AU仓库
                repoGuids.push(auRepoGuid);
                dataValues.push([new Variant(packetDescription)]);
            }
            // 子实例
            repoGuids.push(childInstanceGuid);
            dataValues.push([new Variant(packetDescription)]);
        }

        for (const auRepoGuid of rootInstanceGuidAndChildAuRepoGuidsMap.get(rootInstanceGuid))
        {
            if (!repoGuidAndInfoMap.has(auRepoGuid) || repoGuidAndInfoMap.get(auRepoGuid).errorCode != Enum_ErrorCode.SUCCESS) { continue }
            // 根实例的子AU仓库
            repoGuids.push(auRepoGuid);
            dataValues.push([new Variant(packetDescription)]);
        }

        // 根实例
        repoGuids.push(rootInstanceGuid);
        dataValues.push([new Variant(packetDescription)]);
    }

    if (repoGuids.length == 0)
    {
        console.log(`[W] <实例和AU仓库_提交版本> :: 待提交版本的仓库数量为 0`);
        return true;
    }

    let guidsBatch = [];
    let dataValuesBatch = [];
    const packetResults = [];
    for (let i = 0; i < repoGuids.length; i++)
    {
        const repoGuid = repoGuids[i];
        if (repoGuidAndInfoMap.get(repoGuid).errorCode != Enum_ErrorCode.SUCCESS) { continue; }
        guidsBatch.push(repoGuid);
        dataValuesBatch.push(dataValues[i]);
        if ($Variable.abortPacket)
        {
            _compileAbortedGuids(guidsBatch);
            break;
        }
        if (guidsBatch.length >= concurrentPacketCount || i == repoGuids.length - 1)
        {
            const promiseArr = [];
            for (let j = 0; j < guidsBatch.length; j++)
            {
                repoGuidAndInfoMap.get(guidsBatch[j]).taskStatus = Enum_taskStatus.Running;
                promiseArr.push(_asyncCreatePacket([guidsBatch[j]], dataFields, [dataValuesBatch[j]]));
            }

            const results = await Promise.allSettled(promiseArr);
            guidsBatch = [];
            dataValuesBatch = [];
            packetResults.push(...results);
        }
    }
    return true;
}


