// 初始化仓库信息, 一定要按照顺序层层初始化仓库信息
async function _initRepos(rootInstanceGuids)
{
    let filter = "";
    let returnFields = ["$name", "$guid", "$parentguid", "$description"];
    let limit = 100;
    let funcDesc = "";

    if (rootInstanceGuids.length == 0)
    {
        _showMessage(`rootInstanceGuids 为空`);
        return;
    }

    // 初始化根实例仓库
    {
        returnFields = ["$name", "$guid", "$parentguid", "$description"];
        limit = 1000;
        funcDesc = "查询根实例仓库信息列表";
        const repos = await _queryReposByGuids(rootInstanceGuids, returnFields, { limit, funcDesc });
        if (!repos)
        {
            _showMessage(`${funcDesc} :: 失败`);
            return false;
        }

        if (repos.length != rootInstanceGuids.length)
        {
            _showMessage(`${funcDesc} :: 仓库数量(${repos.length}个)与rootInstanceGuids(${rootInstanceGuids.length}个)数量不一致`);
            return false;
        }

        repos.forEach(item =>
        {
            const guid = item.$guid;
            const fullName = item.$name;
            const repoType = Enum_RepoType.ROOT_INSTANCE;
            repoGuidAndInfoMap.set(guid, Object.assign({}, item, { repoType, fullName }));
            rootInstanceGuidAndChildAuRepoGuidsMap.set(guid, []);
            rootInstanceGuidAndChildInstanceGuidsMap.set(guid, []);
        });
    }

    // 初始化根实例仓库的子AU仓库
    if (rootInstanceGuids.length > 0)
    {
        filter = `$label1 == "50"`;
        returnFields = ["$name", "$guid", "$parentguid", "$description"];
        limit = 200;
        funcDesc = "查询根实例仓库的子AU仓库列表";
        const repos = await _queryChildReposByParentGuids(rootInstanceGuids, filter, returnFields, { limit, funcDesc });
        if (!repos)
        {
            _showMessage(`${funcDesc} :: 失败`);
            return;
        }

        repos.forEach(item =>
        {
            const guid = item.$guid;
            const rootInstanceGuid = item.$parentguid;
            const fullName = repoGuidAndInfoMap.get(rootInstanceGuid)["fullName"] + "//" + item.$name;
            const repoType = Enum_RepoType.AU_ROOT_INSTANCE;
            repoGuidAndInfoMap.set(guid, Object.assign({}, item, { repoType, fullName }));
            rootInstanceGuidAndChildAuRepoGuidsMap.get(rootInstanceGuid).push(guid);
            childAuRepoGuidAndRootInstanceGuidMap.set(guid, rootInstanceGuid);
        });
    }


    // 初始化子实例仓库
    const childInstanceGuids = [];
    if (rootInstanceGuids.length > 0)
    {
        filter = `$label1 == "10" && $label2 == "1"`;
        returnFields = ["$name", "$guid", "$parentguid", "$description"];
        limit = 100;
        funcDesc = "查询子实例仓库列表";
        const repos = await _queryChildReposByParentGuids(rootInstanceGuids, filter, returnFields, { limit, funcDesc });
        if (!repos)
        {
            _showMessage(`${funcDesc} :: 失败`);
            return;
        }

        repos.forEach(item =>
        {
            const guid = item.$guid;
            const rootInstanceGuid = item.$parentguid;
            const fullName = repoGuidAndInfoMap.get(rootInstanceGuid)["fullName"] + "//" + item.$name;
            const repoType = Enum_RepoType.CHILD_INSTANCE;
            childInstanceGuids.push(guid);
            repoGuidAndInfoMap.set(guid, Object.assign({}, item, { repoType, fullName }));
            rootInstanceGuidAndChildInstanceGuidsMap.get(rootInstanceGuid).push(guid);
            childInstanceGuidAndRootInstanceGuidMap.set(guid, rootInstanceGuid);
            childInstanceGuidAndChildAuRepoGuidsMap.set(guid, []);
        });
    }


    // 初始化子实例仓库的子AU仓库
    if (childInstanceGuids.length > 0)
    {
        filter = `$label1 == "50"`;
        returnFields = ["$name", "$guid", "$parentguid", "$description"];
        limit = 200;
        funcDesc = "查询子实例仓库的子AU仓库列表";
        const repos = await _queryChildReposByParentGuids(childInstanceGuids, filter, returnFields, { limit, funcDesc });
        if (!repos)
        {
            _showMessage(`${funcDesc} :: 失败`);
            return;
        }

        repos.forEach(item =>
        {
            const guid = item.$guid;
            const childInstanceGuid = item.$parentguid;
            const fullName = repoGuidAndInfoMap.get(childInstanceGuid)["fullName"] + "//" + item.$name;
            const repoType = Enum_RepoType.AU_CHILD_INSTANCE;
            repoGuidAndInfoMap.set(guid, Object.assign({}, item, { repoType, fullName }));
            childInstanceGuidAndChildAuRepoGuidsMap.get(childInstanceGuid).push(guid);
            childAuRepoGuidAndChildInstanceGuidMap.set(guid, childInstanceGuid);
        });
    }

    // 处理仓库数据
    _compileRepoInfo();

    return true;
}

function _compileRepoInfo()
{

    // 计算各个层级(时空仓库/根实例仓库/子实例仓库)总的仓库数量

    // 根实例的子AU仓库
    for (const childAuRepoGuid of childAuRepoGuidAndRootInstanceGuidMap.keys())
    {
        repoGuidAndInfoMap.get(childAuRepoGuid)["totalCount"] = 1;
    }

    // 子实例的子AU仓库
    for (const childAuRepoGuid of childAuRepoGuidAndChildInstanceGuidMap.keys())
    {
        repoGuidAndInfoMap.get(childAuRepoGuid)["totalCount"] = 1;
    }

    // 子实例
    for (const [childInstanceGuid, childAuRepoGuids] of childInstanceGuidAndChildAuRepoGuidsMap)
    {
        let totalCountOfChildInstance = 1;
        totalCountOfChildInstance += childAuRepoGuids.length;
        repoGuidAndInfoMap.get(childInstanceGuid)["totalCount"] = totalCountOfChildInstance;
    }

    // 根实例
    for (const [rootInstanceGuid, childInstanceGuids] of rootInstanceGuidAndChildInstanceGuidsMap)
    {
        let totalCountOfRootInstance = 1;
        totalCountOfRootInstance += rootInstanceGuidAndChildAuRepoGuidsMap.get(rootInstanceGuid).length;
        for (const childInstanceGuid of childInstanceGuids)
        {
            totalCountOfRootInstance += repoGuidAndInfoMap.get(childInstanceGuid)["totalCount"];
        }
        repoGuidAndInfoMap.get(rootInstanceGuid)["totalCount"] = totalCountOfRootInstance;
    }


    // 处理仓库数据
    for (const [guid, repoInfo] of repoGuidAndInfoMap)
    {
        const newInfo = Object.assign({}, {
            name: repoInfo.$name,
            guid: repoInfo.$guid,
            description: repoInfo.$description,
            parentGuid: repoInfo.$parentguid,
            fullName: repoInfo.fullName,
            repoType: repoInfo.repoType,
            totalCount: repoInfo.totalCount,
            completedCount: 0,
            children: [],
            progress: {
                type: "progress",
                value: 0,
                strokeWidth: 16,
                textInside: true,
                showText: true,
                status: "warning" // success/exception/warning
            },
            taskStatus: Enum_taskStatus.NotStarted,
            packetVersion: 0,
            errorCode: 0,
            errorMessage: "",
        });
        repoGuidAndInfoMap.set(guid, newInfo);
    }
}

