            repoGuidAndInfoMap.get(rootInstanceGuid).children.push(repoGuidAndInfoMap.get(childInstanceGuid));
        }
        tableData.push(repoGuidAndInfoMap.get(rootInstanceGuid));
    }
    return tableData;
}


